<script setup lang="ts">
  const { modelValue, autofocus = false } = defineProps<{
    id?: string;
    flat?: boolean;
    label?: string;
    placeholder?: string;
    modelValue: unknown;
    autofocus?: boolean;
  }>();

  const emit = defineEmits<{
    (event: 'update:modelValue', value: unknown): void;
  }>();

  let value = $computed({
    get: () => modelValue,
    set: v => emit('update:modelValue', v),
  });
</script>

<template>
  <Label
    :id="id"
    v-slot="{ id: labelId }"
    class="flex-col gap-1"
  >
    <span class="text-xs">{{ label }}</span>
    <div class="relative">
      <select
        :id="labelId"
        v-model="value"
        :label="label"
        :class="[
          'block',
          'p-2',
          'rounded',
          'w-full',
          'h-10',
          'border-none',
          'focus:ring-0',
          'uppercase',
          !flat && 'shadow shadow-current',
          flat ? 'bg-secondary/5' : 'bg-lower/5',
          'bg-none',
        ]"
        :autofocus="autofocus"
      >
        <option
          v-if="placeholder"
          disabled
          hidden
          :value="undefined"
        >
          {{ placeholder }}
        </option>
        <option
          v-if="placeholder"
          disabled
          hidden
          :value="null"
        >
          {{ placeholder }}
        </option>

        <slot></slot>
      </select>
      <Icon
        name="fa6-solid:chevron-down"
        class="absolute right-3 top-3 text-current pointer-events-none text-sm"
      />
    </div>
  </Label>
</template>

<style lang="scss" scoped>
  select ::v-deep(*) {
    @apply bg-back;
  }
</style>
