<script lang="ts">
  function getFrequencyOptions() {
    const now = Temporal.Now.plainDateISO();
    return {
      Permanent: { type: FrequencyType.ALWAYS },
      OneTime: {
        type: FrequencyType.ONE_TIME,
        date: now.toJSON().slice(0, 10),
      },
      Daily: { type: FrequencyType.DAILY },
      Weekly: {
        type: FrequencyType.WEEKLY,
        weekday: now.dayOfWeek,
      },
      MonthlyByDay: {
        type: FrequencyType.MONTHLY,
        by: IntervalUnit.DAY,
        day: now.day,
      },
    };
  }
</script>

<script setup lang="ts">
  defineProps<{ available: IAvailable }>();

  // let scheduled = $ref(false);
  let frequencyOptions = $ref(getFrequencyOptions());

  const { PlainTime } = Temporal;
</script>

