<script setup lang="ts">
  const { modelValue, autofocus = false } = defineProps<{
    id?: string;
    flat?: boolean;
    label?: string;
    placeholder?: string;
    modelValue: null | Temporal.PlainTime | Temporal.PlainDateTime;
    min?: Temporal.PlainTime | Temporal.PlainDateTime;
    max?: Temporal.PlainTime | Temporal.PlainDateTime;
    autofocus?: boolean;
  }>();

  function focus(el: HTMLElement) {
    if (autofocus) {
      el.focus();
    }
  }

  function click(id: string) {
    (document.getElementById(id) as null | HTMLInputElement)?.showPicker();
  }

  const emit = defineEmits<{
    (
      event: 'update:modelValue',
      value: null | Temporal.PlainTime | Temporal.PlainDateTime,
    ): void;
  }>();

  let value = $computed({
    get: () =>
      modelValue instanceof Temporal.PlainDateTime
        ? modelValue.toPlainTime()
        : modelValue,
    set: v =>
      emit(
        'update:modelValue',
        !v
          ? null
          : modelValue instanceof Temporal.PlainDateTime
          ? modelValue.withPlainTime(Temporal.PlainTime.from(v))
          : Temporal.PlainTime.from(v),
      ),
  });

  const timeFormatter = new Intl.DateTimeFormat(undefined, {
    hour: 'numeric',
    minute: 'numeric',
    second: undefined,
    timeZone: Temporal.Now.timeZone().id,
  });

  const PlainDateTime = Temporal.PlainDateTime;
</script>

<template>
  <Label
    :id="id"
    v-slot="{ id: labelId }"
    :label="label"
    class="flex-col gap-1"
  >
    <div
      v-mounted="focus"
      tabindex="0"
      :class="[
        'h-10',
        'p-2',
        'w-full',
        'flex',
        'items-center',
        'relative',
        'rounded',
        'focus-visible:outline-none',
        !flat && 'shadow shadow-current',
        flat ? 'bg-secondary/5' : 'bg-lower/5',
      ]"
      @keyup.enter="click(labelId)"
    >
      <input
        :id="labelId"
        v-model="value"
        :label="label"
        type="time"
        class="absolute left-0 top-0 w-full h-full opacity-0"
        :min="
          (min instanceof PlainDateTime ? min.toPlainDate() : min)?.toJSON()
        "
        :max="
          (max instanceof PlainDateTime ? max.toPlainDate() : max)?.toJSON()
        "
        tabindex="-1"
      />

      <span class="block flex-grow">
        <span v-if="value">
          {{ timeFormatter.format(value) }}
        </span>
        <span v-else>
          {{ placeholder }}
        </span>
      </span>

      <Icon
        class="mr-1"
        name="fa6-solid:clock"
      />
      <!-- <Button
        v-if="value"
        class="absolute left-0 shadow-none border-none hover:text-primary z-10"
        @click="value = null"
      >
        <Icon name="fa6-solid:xmark" />
      </Button> -->
    </div>
  </Label>
</template>

